#include \"kernel_operator.h\"

using namespace AscendC;

extern \"C\" __global__ __aicore__ void ca6k_03088_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling) {
  GET_TILING_DATA(td, tiling);
  uint32_t rows = td.rows;
  uint32_t cols = td.cols;
  uint32_t blockIdx = GetBlockIdx();
  if (blockIdx >= cols) return;

  GlobalTensor<float> xGm;
  xGm.SetGlobalBuffer((__gm__ float *)x, rows * cols);
  GlobalTensor<float> yGm;
  yGm.SetGlobalBuffer((__gm__ float *)y, cols);
  GlobalTensor<float> wsGm;
  wsGm.SetGlobalBuffer((__gm__ float *)workspace, rows * cols);

  // Copy column from input to workspace in tiles via local buffer
  const uint32_t tileSize = 2048; // smaller than UB budget
  for (uint32_t offset = 0; offset < rows; offset += tileSize) {
    uint32_t copyLen = (offset + tileSize <= rows) ? tileSize : (rows - offset);
    auto local = LocalTensor<float>(tileSize * sizeof(float));
    DataCopy(local, xGm[blockIdx * rows + offset], copyLen);
    DataCopy(wsGm[blockIdx * rows + offset], local, copyLen);
  }

  // Hoare's QuickSelect on workspace column to find lower median
  int32_t left = 0;
  int32_t right = static_cast<int32_t>(rows) - 1;
  int32_t k = (rows - 1) / 2; // lower median index
  while (left < right) {
    float pivot = wsGm[blockIdx * rows + left];
    int32_t i = left - 1;
    int32_t j = right + 1;
    while (i < j) {
      do { i++; } while (wsGm[blockIdx * rows + i] < pivot);
      do { j--; } while (wsGm[blockIdx * rows + j] > pivot);
      if (i < j) {
        float tmp = wsGm[blockIdx * rows + i];
        wsGm[blockIdx * rows + i] = wsGm[blockIdx * rows + j];
        wsGm[blockIdx * rows + j] = tmp;
      }
    }
    if (k <= j)
      right = j;
    else
      left = j + 1;
  }

  float median = wsGm[blockIdx * rows + k];
  yGm[blockIdx] = median;
}
